import React, { useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { useQuery, useMutation, useQueryClient } from "react-query";
import { employeeAPI } from "../utils/api";
import LoadingSpinner from "../components/common/LoadingSpinner";
import { ArrowLeftIcon } from "@heroicons/react/24/outline";
import { SparklesIcon } from "@heroicons/react/24/solid";
import toast from "react-hot-toast";
import clsx from "clsx";
const TABS = ["Overview","AI Insights"];
export default function EmployeeDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const qc = useQueryClient();
  const [tab, setTab] = useState("Overview");
  const [aiLoading, setAiLoading] = useState(false);
  const { data: emp, isLoading } = useQuery(["employee", id], () => employeeAPI.getById(id).then(r => r.data.data));
  const runAttrition = async () => {
    setAiLoading(true);
    try { await employeeAPI.getAttritionRisk(id); toast.success("Analysis complete"); qc.invalidateQueries(["employee", id]); }
    catch { toast.error("Analysis failed"); }
    finally { setAiLoading(false); }
  };
  if (isLoading) return <LoadingSpinner />;
  if (!emp) return <div className="card text-center py-16 text-slate-500">Employee not found</div>;
  const riskColor = emp.aiAttritionScore >= 70 ? "text-red-600 bg-red-50 border-red-200" : emp.aiAttritionScore >= 40 ? "text-amber-600 bg-amber-50 border-amber-200" : "text-emerald-600 bg-emerald-50 border-emerald-200";
  return (
    <div className="space-y-5 animate-in">
      <div className="flex items-start gap-4">
        <button onClick={() => navigate(-1)} className="p-2 rounded-lg hover:bg-slate-100 mt-0.5"><ArrowLeftIcon className="w-4 h-4" /></button>
        <div className="flex items-center gap-4 flex-wrap">
          <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-primary-400 to-purple-500 flex items-center justify-center text-white text-xl font-bold flex-shrink-0">{emp.firstName[0]}{emp.lastName[0]}</div>
          <div><h1 className="page-title">{emp.firstName} {emp.lastName}</h1><div className="flex items-center gap-3 mt-1 text-sm text-slate-500"><span className="font-mono text-xs bg-slate-100 px-2 py-0.5 rounded">{emp.employeeId}</span><span className={`badge ${emp.employmentStatus==="active"?"badge-success":"badge-neutral"}`}>{emp.employmentStatus}</span></div></div>
        </div>
      </div>
      {emp.aiAttritionScore > 0 && <div className={clsx("rounded-xl px-4 py-3 flex items-center gap-3 border", riskColor)}><SparklesIcon className="w-4 h-4 flex-shrink-0" /><p className="text-sm font-semibold">AI Attrition Risk: {Math.round(emp.aiAttritionScore)}% — {emp.aiAttritionScore>=70?"HIGH RISK":emp.aiAttritionScore>=40?"MEDIUM RISK":"LOW RISK"}</p></div>}
      <div className="flex gap-1 border-b border-slate-200">{TABS.map(t => (<button key={t} onClick={() => setTab(t)} className={clsx("px-4 py-2 text-sm font-medium border-b-2 -mb-px transition-colors", tab===t?"border-primary-500 text-primary-600":"border-transparent text-slate-500 hover:text-slate-700")}>{t}</button>))}</div>
      {tab==="Overview"&&<div className="grid grid-cols-1 md:grid-cols-2 gap-5"><div className="card"><h3 className="section-title mb-4">Details</h3><div className="space-y-3">{[["Email",emp.email],["Phone",emp.phone||"—"],["Department",emp.department?.name||"—"],["Employment Type",emp.employmentType?.replace("_"," ")],["Join Date",emp.joinDate],["Salary",emp.salary?`₹${Number(emp.salary).toLocaleString("en-IN")}`:"—"]].map(([k,v])=>(<div key={k} className="flex justify-between py-2 border-b border-slate-100 last:border-0 text-sm"><span className="text-slate-500">{k}</span><span className="font-medium text-slate-800 capitalize">{v}</span></div>))}</div></div></div>}
      {tab==="AI Insights"&&<div className="card ai-glow"><div className="flex items-center justify-between mb-4"><div className="flex items-center gap-2"><SparklesIcon className="w-5 h-5 text-primary-500" /><h3 className="section-title">Attrition Analysis</h3></div><button onClick={runAttrition} disabled={aiLoading} className="btn-primary text-sm">{aiLoading?"Analyzing…":"Run Analysis"}</button></div>
      {emp.aiInsights?.attrition?(<div className="space-y-4"><div className="flex items-center gap-4"><div className="relative w-20 h-20"><svg viewBox="0 0 36 36" className="w-20 h-20 -rotate-90"><path d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="#e2e8f0" strokeWidth="3"/><path d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke={emp.aiAttritionScore>=70?"#ef4444":emp.aiAttritionScore>=40?"#f59e0b":"#10b981"} strokeWidth="3" strokeDasharray={`${emp.aiAttritionScore},100`}/></svg><div className="absolute inset-0 flex items-center justify-center"><span className="text-sm font-bold text-slate-900">{Math.round(emp.aiAttritionScore)}%</span></div></div><div><p className="font-semibold text-slate-900">{emp.aiAttritionScore>=70?"High Risk":emp.aiAttritionScore>=40?"Medium Risk":"Low Risk"}</p></div></div>
      {emp.aiInsights.attrition.recommendations?.length>0&&<div><p className="text-sm font-semibold text-slate-700 mb-2">Recommendations</p><ul className="space-y-1.5">{emp.aiInsights.attrition.recommendations.map((r,i)=>(<li key={i} className="flex items-start gap-2 text-sm text-slate-600"><span className="text-primary-500 mt-0.5">→</span>{r}</li>))}</ul></div>}</div>):(<div className="flex flex-col items-center py-8 text-center"><p className="text-slate-500 text-sm">Click Run Analysis to generate AI attrition insights.</p></div>)}</div>}
    </div>
  );
}
